class TextEditor {
public:
    TextEditor() {

    }

    void addText(string text) {
        left = left + text;
        cursor += text.size();
    }

    int deleteText(int k) {
        int del = min(k, (int)left.size());
        left = left.substr(0, left.size() - del);
        cursor -= del;
        return del;
    }

    string cursorLeft(int k) {
        cursor = max(0, cursor - k);
        return left.substr(max(0, (int)left.size() - 10), min(10, (int)left.size()));
    }

    string cursorRight(int k) {
        cursor = min((int)left.size() + (int)right.size(), cursor + k);
        int lsize = left.size();
        int move = min(k, (int)right.size());
        for(int i = 0; i < move; i++) {
            left += right[0];
            right.erase(0, 1);
        }
        return left.substr(max(0, lsize - 10), min(10, lsize + move));
    }
private:
    string left, right;
    int cursor = 0;
};
